module multi_pipe_4bit(
    input clk,
    input rst_n,
    input mul_a,
    input mul_b,
    output mul_out
);

    reg [7:0] pp[0:3];
    reg [7:0] acc[0:3];

    integer i;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            for (i = 0; i < 4; i = i + 1) begin
                pp[i] <= 8'b0;
                acc[i] <= 8'b0;
            end
        end else begin
            // Generate partial products
            for (i = 0; i < 4; i = i + 1) begin
                pp[i] <= mul_a * mul_b[i];
            end

            // Accumulate partial products
            acc[0] <= pp[0];
            for (i = 1; i < 4; i = i + 1) begin
                acc[i] <= acc[i-1] + pp[i];
            end
        end
    end

    assign mul_out = acc[3];

endmodule
